input.newString:
export function formatTitle(value, mode = 'plain') {
  if (mode === 'upper') return value.toUpperCase()
  if (mode === 'lower') return value.toLowerCase()
  if (mode === 'title') {
    return value
      .split(' ')
      .map((word) => {
        const capitalized = word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()
        return capitalized
      })
      .join(' ')
  }
  return value
}

